import React, { useState } from "react";
import axios from "axios";

function AnimalDiseasePredictor() {
  const [animal, setAnimal] = useState("Cow");
  const [symptoms, setSymptoms] = useState({});
  const [result, setResult] = useState(null);

  const symptomList = [
    "Fever",
    "Mouth_Lesions",
    "Lameness",
    "Milk_Drop",
    "Skin_Nodules",
    "Diarrhea",
    "Cough",
    "Loss_Appetite"
  ];

  const handleCheckbox = (symptom) => {
    setSymptoms({
      ...symptoms,
      [symptom]: symptoms[symptom] ? 0 : 1
    });
  };

  const handleSubmit = async () => {
    const payload = {
  Animal: animal,
  Fever: symptoms.Fever || 0,
  Mouth_Lesions: symptoms.Mouth_Lesions || 0,
  Lameness: symptoms.Lameness || 0,
  Milk_Drop: symptoms.Milk_Drop || 0,
  Skin_Nodules: symptoms.Skin_Nodules || 0,
  Diarrhea: symptoms.Diarrhea || 0,
  Cough: symptoms.Cough || 0,
  Loss_Appetite: symptoms.Loss_Appetite || 0
};

    try {
      const res = await axios.post(
        "http://127.0.0.1:5000/predict-animal-disease",
        payload
      );
      setResult(res.data);
    } catch (err) {
      alert("Server error");
    }
  };

  return (
    <div className="min-h-screen bg-orange-50 py-10 px-4">
      <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-xl">
        <h2 className="text-3xl font-bold text-orange-700 mb-6">
          Animal Disease Predictor
        </h2>

        <select
          value={animal}
          onChange={(e) => setAnimal(e.target.value)}
          className="w-full border p-3 rounded-lg mb-6"
        >
          <option>Cow</option>
          <option>Goat</option>
          <option>Sheep</option>
        </select>

        <div className="grid grid-cols-2 gap-3 mb-6">
          {symptomList.map((symptom) => (
            <label key={symptom} className="flex items-center gap-2">
              <input
                type="checkbox"
                onChange={() => handleCheckbox(symptom)}
              />
              {symptom.replace("_", " ")}
            </label>
          ))}
        </div>

        <button
          onClick={handleSubmit}
          className="w-full bg-orange-600 text-white py-3 rounded-lg hover:bg-orange-700"
        >
          Predict Disease
        </button>

        {result && (
          <div className="mt-6 bg-orange-50 p-4 rounded-lg">
            <p className="text-lg font-bold">
              Disease: {result.predicted_disease}
            </p>
            <p className="text-gray-700">
              Treatment: {result.treatment}
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

export default AnimalDiseasePredictor;
